import re,itertools
t=open('report.md').read()
body=t.split('## References')[0]
body=re.sub(r'^#.*$','',body,flags=re.M)
# move citation markers after the period so splitting works
norm=re.sub(r'\.((?:\[\d+\])+)', r'\1.', body)
sents=[s.strip() for s in re.split(r'(?<=[.!?])\s+', norm) if len(s.split())>5]
def key(s): return frozenset(re.findall(r'\[(\d+)\]',s))
def toks(s): return set(w.lower() for w in re.findall(r'[a-zA-Z]{4,}',s))
print("sentences:",len(sents))
strict=[];loose=[]
for a,b in itertools.combinations(sents,2):
    ka,kb=key(a),key(b); ta,tb=toks(a),toks(b)
    if not ta or not tb: continue
    ov=len(ta&tb)/min(len(ta),len(tb))
    if ka and ka==kb and ov>0.8: strict.append((round(ov,2),a[:80],b[:80]))
    elif ov>0.6 and ka and kb and (ka&kb): loose.append((round(ov,2),a[:80],b[:80]))
print("LEVER'S OWN CRITERION (same [n] set + >0.8): ",len(strict))
for d in strict: print("  ",d)
print("looser (shared [n] + >0.6):",len(loose))
for d in loose[:8]: print("  ",d)
# the specific claimed dupes
for pat in [r'1\.8%', r'46%', r'5\.4%', r'Noy', r'Eloundou']:
    hits=[s for s in sents if re.search(pat,s)]
    print(f"--- '{pat}': {len(hits)} sentences")
    for h in hits: print("    ", h[:110])
